render_strategy.source:
{
  decorators: [Story => <Story />],
  args: {
    ...defaultArgs,
    ratio: "1",
    isCentered: true,
    title: "This is a title placeholder"
  },
  argTypes: {
    ratio: {
      description: "The ratio of the image",
      control: "select",
      options: ["1/1", "16/9", "21/9", "4/3", "16/10"]
    },
    isCentered: {
      description: "If the content is centered",
      control: "boolean"
    },
    density: {
      description: "The density of the card",
      control: "select",
      options: Object.values(CardDensity)
    }
  },
  render: args => {
    return <Card {...args} type={CardType.LIST}>
        <Card.Media ratio={args.ratio}>
          <Image src={sanofiImage} alt="Sanofi promotional image featuring a new medication" />
        </Card.Media>
        <Card.Section>
          <Card.Content isCentered={args.isCentered} category="Eyebrow One (i.e Category)" date="Eyebrow Two (i.e Date)" title={<Title variant={args.titleSize}>{args.title}</Title>} subText="Lorem ipsum dolor sit amet, " buttonSlot={args.withButtonIcon && <Card.Button icon={IconName.MORE_VERT} onClick={() => notify(args)} aria-label="More actions Card List Image View" />} />
          <Card.Action isCentered={args.isCentered}>
            <LinkStandalone href={sanofiUrl} size={LinkSize.SMALL}>
              Standalone link
            </LinkStandalone>
          </Card.Action>
        </Card.Section>
      </Card>;
  }
}
